const extractionPrompt = "You are a Purchase Order data extraction specialist. Extract ONLY facts explicitly printed on the document. Do NOT invent values.

Return a single JSON object with this structure:
{
  "document_brand": "",
  "po_number": "",
  "vendor_no": "",
  "supplier_no": "",
  "factory_no": "",
  "style_no": "",
  "product_description": "",
  "season": "",
  "colour": "",
  "currency": "",
  "country_of_origin": "",
  "port_of_departure": "",
  "lading_port": "",
  "destination_location": "",
  "order_date": "",
  "payment_terms": "",
  "incoterm": "",
  "items": [],
  "deliveries": [],
  "prepacks": [],
  "ratio_packs": [],
  "missing_fields": []
}

RULES:
1. document_brand = company name at top of document (e.g. BrightKids, ThreadHaven, Raj International Sourcing)
2. vendor_no = field labelled Vendor on document
3. supplier_no = field labelled Supplier No
4. Multiple deliveries = populate deliveries array, each with shipment_date and items array
5. Each item in deliveries.items must have: size, barcode, cost_price, retail_price, order_qty, cartons
6. Prepacks = populate prepacks array with prepack_id and sizes array
7. Ratio packs (Pack A/B) = populate ratio_packs array with pack_name, itf_barcode, qty_of_packs, sizes array
8. Missing fields = leave as empty string and add field name to missing_fields array
9. Return ONLY the JSON object, no markdown, no explanation
10. All numbers as strings exactly as printed";

const items = $input.all();
const results = [];

for (const item of items) {
  const pdfBase64 = item.json.body?.pdf_base64 || item.json.pdf_base64;
  const filename = item.json.body?.filename 
    || item.json.filename 
    || item.json.query?.filename 
    || item.json.headers?.filename 
    || item.json.params?.filename 
    || 'unknown.pdf';

  if (!pdfBase64) {
    results.push({ json: { success: false, filename, error: 'No PDF data received' } });
    continue;
  }

  results.push({
    json: {
      filename,
      requestBody: {
        model: 'claude-sonnet-4-5',
        max_tokens: 4000,
        messages: [{
          role: 'user',
          content: [
            { type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdfBase64 } },
            { type: 'text', text: extractionPrompt }
          ]
        }]
      }
    }
  });
}

return results;

const RULES = [
