  {rule_type:'factory_lookup',source_value:'36229609',target_field:'items.factory_id',target_value:'FCTCN2'}
];

function applyLookup(ruleType, sourceValue, rules) {
  const result = {};
  rules.filter(r => r.rule_type === ruleType && r.source_value.toLowerCase() === (sourceValue || '').toLowerCase())
    .forEach(rule => { result[rule.target_field.split('.').pop()] = rule.target_value; });
  return result;
}

function detectCustomer(facts, rules) {
  const brand = (facts.document_brand || '').toLowerCase();
  for (const rule of rules.filter(r => r.rule_type === 'source_detection')) {
    if (brand.includes(rule.source_value.toLowerCase())) return rule.target_value;
  }
  return null;
}

const results = [];
for (const item of $input.all()) {
  try {
    const filename = item.json.filename || 'unknown.pdf';
    const content = item.json.content || [];
    const rawText = content.filter(b => b.type === 'text').map(b => b.text).join('');
    const cleanJson = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
    const facts = JSON.parse(cleanJson);

    const customerCode = detectCustomer(facts, RULES);
    const headerDefaults = {};
    RULES.filter(r => r.rule_type === 'header_default').forEach(r => { headerDefaults[r.target_field.replace('header.','')] = r.target_value; });
    const divLookup = applyLookup('division_lookup', customerCode, RULES);
    const header = { action: headerDefaults.action || 'NEW', customer_code: customerCode || '', po_num: facts.po_number || '', div_code: divLookup.div_code || '' };
    const seasonLookup = applyLookup('season_lookup', facts.season || '', RULES);
    const incotermLookup = applyLookup('incoterm_lookup', 'FOB', RULES);
    const pr = { issue_date: facts.order_date || '', currency: facts.currency || 'USD', incoterm_code: incotermLookup.incoterm_code || 'FOB', incoterm_text: incotermLookup.incoterm_text || 'FREE ON BOARD', season: seasonLookup.season || facts.season || '' };
    const vendorData = Object.keys(applyLookup('vendor_lookup', facts.vendor_no, RULES)).length > 0 ? applyLookup('vendor_lookup', facts.vendor_no, RULES) : applyLookup('vendor_lookup', facts.supplier_no, RULES);
    const suppliers = [{ supplier_id: '1', vendor_code: vendorData.vendor_code || '', vendor_name: vendorData.vendor_name || '', vendor_currency: vendorData.vendor_currency || '', vendor_inc_code: vendorData.vendor_inc_code || '', vendor_incoterm: vendorData.vendor_incoterm || '' }];
    const countryLookup = applyLookup('country_lookup', facts.country_of_origin, RULES);
    const factoryLookup = applyLookup('factory_lookup', facts.factory_no, RULES);
    const colour = (facts.colour || '').toUpperCase();
    const countryCode = countryLookup.country_of_origin || facts.country_of_origin || '';
    const factoryId = factoryLookup.factory_id || facts.factory_no || '';
    const items = [];
    let itemId = 1;
    if (facts.deliveries && facts.deliveries.length > 0) {
      for (const delivery of facts.deliveries) {
        for (const it of (delivery.items || [])) {
          items.push({ item_id: String(itemId++), supplier_id: '1', style_no: facts.style_no || '', shipment_id: header.po_num, country_of_origin: countryCode, price: it.cost_price || '', factory_id: factoryId, color: colour, size_id: it.size || '' });
        }
      }
    } else if (facts.items && facts.items.length > 0) {
      for (const it of facts.items) {
        items.push({ item_id: String(itemId++), supplier_id: '1', style_no: facts.style_no || '', shipment_id: header.po_num, country_of_origin: countryCode, price: it.cost_price || '', factory_id: factoryId, color: colour, size_id: it.size || '' });
      }
    }
    const portRaw = facts.port_of_departure || facts.lading_port || '';
    const portLookup = applyLookup('port_lookup', portRaw, RULES);
    const destLookup = applyLookup('destination_lookup', facts.destination_location || '', RULES);
    const shipments = facts.deliveries && facts.deliveries.length > 0
      ? facts.deliveries.map((d, i) => ({ shipment_id: String(i+1), port_of_loading: portLookup.port_of_loading || portRaw, port_of_discharge: destLookup.port_of_discharge || '', final_destination: destLookup.final_destination || '' }))
      : [{ shipment_id: '1', port_of_loading: portLookup.port_of_loading || portRaw, port_of_discharge: destLookup.port_of_discharge || '', final_destination: destLookup.final_destination || '' }];
    const prepacks = (facts.prepacks && facts.prepacks.length > 0)
      ? facts.prepacks.map((p, i) => ({ prepack_id: String(i+1), details: (p.sizes||[]).map((s,j) => ({ id: String(j+1), size_id: s.size||'', pack_color: String(i+1) })) }))
      : (facts.ratio_packs && facts.ratio_packs.length > 0)
        ? facts.ratio_packs.map((p, i) => ({ prepack_id: String(i+1), details: (p.sizes||[]).map((s,j) => ({ id: String(j+1), size_id: s.size||'', pack_color: p.pack_name||'' })) }))
        : [];

    results.push({ json: { success: true, filename, purchase_order: { source_file: filename, header, pr, suppliers, items, shipments, prepacks } } });
  } catch(error) {
    results.push({ json: { success: false, filename: item.json.filename || 'unknown', error: error.message, purchase_order: null } });
  }
}
return results;

const required = {
  header: ['action','customer_code','po_num','div_code'],
  pr: ['currency','incoterm_code','incoterm_text','season'],
  suppliers: ['vendor_code','vendor_name','vendor_currency','vendor_inc_code','vendor_incoterm'],
  items: ['style_no','country_of_origin','price','factory_id','color','size_id'],
  shipments: ['port_of_loading','port_of_discharge','final_destination']
};
function validate(transformResult) {
  if (!transformResult.success || !transformResult.purchase_order) {
    return { status: 'failed', purchase_order: null, issues: [{ section: 'pipeline', field: 'transformation', message: transformResult.error || 'Transformation failed' }] };
  }
  const po = transformResult.purchase_order;
  const issues = [];
  for (const f of required.header) { if (!po.header?.[f]) issues.push({ section: 'header', field: f, message: `header.${f} is missing` }); }
  for (const f of required.pr) { if (!po.pr?.[f]) issues.push({ section: 'pr', field: f, message: `pr.${f} is missing` }); }
  (po.suppliers||[]).forEach((s,i) => required.suppliers.forEach(f => { if (!s[f]) issues.push({ section: 'suppliers', field: f, message: `suppliers[${i}].${f} is missing` }); }));
  (po.items||[]).forEach((s,i) => required.items.forEach(f => { if (!s[f]) issues.push({ section: 'items', field: f, message: `items[${i}].${f} is missing` }); }));
  (po.shipments||[]).forEach((s,i) => required.shipments.forEach(f => { if (!s[f]) issues.push({ section: 'shipments', field: f, message: `shipments[${i}].${f} is missing` }); }));
  return { status: issues.length === 0 ? 'artifact_ready' : 'needs_review', purchase_order: po, issues };
}
const results = [];
for (const item of $input.all()) {
  results.push({ json: validate(item.json) });
}
return results;
